import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.ufzXw1qY.js";const p=JSON.parse('{"title":"Ultimate Browser Automation & Anti-Bot Bypass","description":"The mandatory protocols for web interactions, DevTools-first coding, and evading bot detection.","frontmatter":{"title":"Ultimate Browser Automation & Anti-Bot Bypass","description":"The mandatory protocols for web interactions, DevTools-first coding, and evading bot detection."},"headers":[],"relativePath":"best-practices/browser-automation.md","filePath":"best-practices/browser-automation.md"}'),i={name:"best-practices/browser-automation.md"};function n(s,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="ultimate-browser-automation-anti-bot-bypass" tabindex="-1">Ultimate Browser Automation &amp; Anti-Bot Bypass <a class="header-anchor" href="#ultimate-browser-automation-anti-bot-bypass" aria-label="Permalink to &quot;Ultimate Browser Automation &amp; Anti-Bot Bypass&quot;">​</a></h1><blockquote><p><strong>Mandate:</strong> Web interaction work must stay inside the approved OpenSIN browser stack. Use <code>webauto-nodriver-mcp</code>, attached Chrome profiles, and verified selectors; do not improvise with legacy browser frameworks or guessed DOM targets.</p></blockquote><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>Standard</th></tr></thead><tbody><tr><td>Allowed tooling</td><td><code>webauto-nodriver-mcp</code>, <code>nodriver</code>, Chrome DevTools Protocol, <code>curl_cffi</code> when TLS impersonation is explicitly required</td></tr><tr><td>Required proof</td><td>DevTools verification, screenshot + vision check after every action, runtime artifacts for failures</td></tr><tr><td>Forbidden</td><td>Playwright, Puppeteer, Selenium, Camoufox, temporary clean profiles, blind selector guesses</td></tr></tbody></table><h2 id="_1-technology-sovereignty-mandate" tabindex="-1">1. Technology sovereignty mandate <a class="header-anchor" href="#_1-technology-sovereignty-mandate" aria-label="Permalink to &quot;1. Technology sovereignty mandate&quot;">​</a></h2><h3 id="what" tabindex="-1">What <a class="header-anchor" href="#what" aria-label="Permalink to &quot;What&quot;">​</a></h3><p>All web interactions, logins, CAPTCHA handling, and scraping tasks must run through <code>webauto-nodriver-mcp</code>, <code>nodriver</code>, CDP, or <code>curl_cffi</code> when the task specifically needs TLS spoofing.</p><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p><code>nodriver</code> attaches to a real Chrome session and reuses genuine cookies, history, and session state. That keeps the interaction close to human browsing behavior and preserves the trust already built into the profile.</p><h3 id="why-not-otherwise" tabindex="-1">Why not otherwise <a class="header-anchor" href="#why-not-otherwise" aria-label="Permalink to &quot;Why not otherwise&quot;">​</a></h3><p>Playwright, Puppeteer, Selenium, and similar stacks expose browser automation fingerprints immediately. They also break the shared Chrome-profile workflow the rest of the fleet depends on.</p><h3 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h3><ul><li><code>webauto-nodriver-mcp</code> for browser control</li><li>the Chrome profile rule for authenticated and trusted sessions</li><li>the vision-gate mandate for post-action verification</li></ul><h3 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><ul><li>Shipping <code>bun add playwright</code> or a similar stack is a protocol violation</li><li>Burning trusted sessions or getting the project flagged by Cloudflare destroys future automation capacity</li></ul><h2 id="_2-devtools-first-workflow" tabindex="-1">2. DevTools-first workflow <a class="header-anchor" href="#_2-devtools-first-workflow" aria-label="Permalink to &quot;2. DevTools-first workflow&quot;">​</a></h2><h3 id="what-1" tabindex="-1">What <a class="header-anchor" href="#what-1" aria-label="Permalink to &quot;What&quot;">​</a></h3><p>Before every click, form fill, or selector change, inspect the live DOM and verify the exact target in DevTools.</p><ol><li>Check the Elements tab for the real <code>id</code>, <code>class</code>, and <code>data-*</code> attributes.</li><li>Validate the selector in Console with <code>document.querySelector(...)</code>; if it returns <code>null</code>, stop.</li><li>Confirm visibility with checks such as <code>element.offsetParent !== null</code> and <code>window.getComputedStyle(el)</code>.</li><li>Read Console errors before triggering the action.</li></ol><h3 id="why-1" tabindex="-1">Why <a class="header-anchor" href="#why-1" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Modern React/Vue/SPAs generate transient classes, overlays, and delayed elements. Guessing selectors from memory creates flaky scripts that only work under lucky timing.</p><h3 id="why-not-otherwise-1" tabindex="-1">Why not otherwise <a class="header-anchor" href="#why-not-otherwise-1" aria-label="Permalink to &quot;Why not otherwise&quot;">​</a></h3><p>Blind automation turns recoverable page-state issues into retries, timeouts, and noisy failures. A selector that is not validated against the live DOM is not ready for production use.</p><h3 id="dependencies-1" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies-1" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h3><p>This workflow depends on screenshot capture, console evidence, and explicit failure logging when a selector cannot be proven.</p><h3 id="consequences-1" tabindex="-1">Consequences <a class="header-anchor" href="#consequences-1" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><ul><li>Unverified selectors are treated as protocol violations</li><li>Empty clicks waste compute, stall flows, and obscure the real page failure</li></ul><h2 id="_3-chrome-profile-discipline" tabindex="-1">3. Chrome profile discipline <a class="header-anchor" href="#_3-chrome-profile-discipline" aria-label="Permalink to &quot;3. Chrome profile discipline&quot;">​</a></h2><h3 id="what-2" tabindex="-1">What <a class="header-anchor" href="#what-2" aria-label="Permalink to &quot;What&quot;">​</a></h3><p>Automation must run inside the documented Chrome profiles for the task. Never switch bot-sensitive work to an empty or temporary profile.</p><table tabindex="0"><thead><tr><th>Profile</th><th>Example use</th><th>Rule</th></tr></thead><tbody><tr><td>Business/admin profile</td><td>Workspace or admin-console operations</td><td>Keep separated from personal and general agent work</td></tr><tr><td>Default / general profile</td><td>Standard agent browsing and known trusted sessions</td><td>Do not reuse for admin-only tasks</td></tr><tr><td>Specialized profile</td><td>Bug bounty, freelancing, or target-specific tasks</td><td>Reserve it for the documented workflow only</td></tr></tbody></table><h3 id="why-2" tabindex="-1">Why <a class="header-anchor" href="#why-2" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Profile separation protects privileged sessions and preserves the trust cookies required for hard targets.</p><h3 id="why-not-otherwise-2" tabindex="-1">Why not otherwise <a class="header-anchor" href="#why-not-otherwise-2" aria-label="Permalink to &quot;Why not otherwise&quot;">​</a></h3><p>A fresh profile starts without trust history and is far more likely to trigger anti-bot systems immediately.</p><h3 id="dependencies-2" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies-2" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h3><p>One live Chrome instance should own one profile directory at a time. If a profile is already active, attach to the existing session instead of trying to force a second writer onto the same profile.</p><h3 id="consequences-2" tabindex="-1">Consequences <a class="header-anchor" href="#consequences-2" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p>Cross-contaminating profiles or wiping trusted state is a long-lived operational failure, not a small local mistake.</p><h2 id="_4-anti-bot-defense-layers" tabindex="-1">4. Anti-bot defense layers <a class="header-anchor" href="#_4-anti-bot-defense-layers" aria-label="Permalink to &quot;4. Anti-bot defense layers&quot;">​</a></h2><h3 id="what-3" tabindex="-1">What <a class="header-anchor" href="#what-3" aria-label="Permalink to &quot;What&quot;">​</a></h3><p>For bot-sensitive or revenue-critical flows, keep all five layers aligned:</p><ol><li><strong>IP reputation</strong> — avoid exposing raw datacenter IPs when the target requires higher trust.</li><li><strong>TLS fingerprint</strong> — use native browser traffic or <code>curl_cffi</code> where transport impersonation matters.</li><li><strong>Browser fingerprint</strong> — stay in visible, real-profile Chrome sessions.</li><li><strong>Behavioral signals</strong> — pace input like a human, not a benchmark script.</li><li><strong>Challenge persistence</strong> — preserve reusable cookies and session state.</li></ol><h3 id="why-3" tabindex="-1">Why <a class="header-anchor" href="#why-3" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Hard targets evaluate transport, browser, behavior, and prior trust together. Failing only one layer can still burn the session.</p><h2 id="verification-checklist" tabindex="-1">Verification checklist <a class="header-anchor" href="#verification-checklist" aria-label="Permalink to &quot;Verification checklist&quot;">​</a></h2><ul><li>[ ] Approved browser tooling was used end-to-end</li><li>[ ] Every selector was verified against the live DOM before use</li><li>[ ] The correct Chrome profile was documented or reused</li><li>[ ] Screenshot + vision evidence exists after each critical action</li><li>[ ] Bot-sensitive steps use realistic pacing and preserve session state</li></ul><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="/best-practices/page-pattern.html">Best-Practice Page Pattern</a></li><li><a href="/best-practices/testing.html">Testing</a></li><li><a href="/best-practices/agent-design.html">Agent Design</a></li></ul><hr><p><em>Last updated:</em> 2026-04-21<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Vision-Gate</strong></td><td>-7.0</td><td>KEINE Web-Aktion ohne Screenshot + Vision-Check</td></tr><tr><td><strong>DevTools-First</strong></td><td>-1.0</td><td>JEDER CSS-Selektor via DevTools verifizieren</td></tr><tr><td><strong>Technologie-Souveränität</strong></td><td>-2.0</td><td>nodriver + Chrome Profil — Playwright/etc. verboten</td></tr><tr><td><strong>Bun-Only</strong></td><td>-1.5</td><td><code>bun install</code> / <code>bun run</code> — npm verboten</td></tr></tbody></table>',54)])])}const f=t(i,[["render",n]]);export{p as __pageData,f as default};
